```typescript
export type TelemetryStreamState =
  | { status: "none" }
  | { status: "open"; id: string; samples: number }
  | { status: "sealed"; id: string; samples: number; sealedAt: string };

export type TelemetryStreamCommand =
  | { type: "open"; id: string }
  | { type: "ingest"; value: number }
  | { type: "seal"; at: string };

export type TelemetryStreamEvent =
  | { type: "TelemetryStreamOpened"; id: string }
  | { type: "TelemetrySampleIngested"; value: number }
  | { type: "TelemetryStreamSealed"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const telemetryStreamDecider: Decider<TelemetryStreamCommand, TelemetryStreamEvent, TelemetryStreamState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "none") throw new DomainError("ALREADY_OPEN");
        return [{ type: "TelemetryStreamOpened", id: command.id }];
      case "ingest":
        if (state.status !== "open") throw new DomainError("NOT_OPEN");
        if (!Number.isFinite(command.value)) throw new DomainError("BAD_VALUE");
        return [{ type: "TelemetrySampleIngested", value: command.value }];
      case "seal":
        if (state.status === "none") throw new DomainError("NEVER_OPENED");
        if (state.status === "sealed") throw new DomainError("ALREADY_SEALED");
        return [{ type: "TelemetryStreamSealed", at: command.at }];
      default: {
        const _n: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "TelemetryStreamOpened":
        return { status: "open", id: event.id, samples: 0 };
      case "TelemetrySampleIngested":
        if (state.status !== "open") return state;
        return { ...state, samples: state.samples + 1 };
      case "TelemetryStreamSealed":
        if (state.status !== "open") return state;
        return { status: "sealed", id: state.id, samples: state.samples, sealedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
