```typescript
export type FleetVehicleState =
  | { status: "unknown" }
  | { status: "idle"; id: string; plate: string }
  | { status: "assigned"; id: string; plate: string; driverId: string }
  | { status: "retired"; id: string; plate: string };

export type FleetVehicleCommand =
  | { type: "enroll"; id: string; plate: string }
  | { type: "assign"; driverId: string }
  | { type: "retire"; reason: string };

export type FleetVehicleEvent =
  | { type: "FleetVehicleEnrolled"; id: string; plate: string }
  | { type: "FleetVehicleAssigned"; driverId: string }
  | { type: "FleetVehicleRetired"; reason: string };

export class FleetError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const fleetVehicleDecider: Decider<FleetVehicleCommand, FleetVehicleEvent, FleetVehicleState> = {
  initialState: { status: "unknown" },
  decide(command, state) {
    switch (command.type) {
      case "enroll":
        if (state.status !== "unknown") throw new FleetError("ALREADY_ENROLLED");
        return [{ type: "FleetVehicleEnrolled", id: command.id, plate: command.plate }];
      case "assign":
        if (state.status === "retired") throw new FleetError("RETIRED");
        if (state.status === "unknown") throw new FleetError("NOT_ENROLLED");
        return [{ type: "FleetVehicleAssigned", driverId: command.driverId }];
      case "retire":
        if (state.status === "retired") throw new FleetError("ALREADY_RETIRED");
        if (state.status === "unknown") throw new FleetError("NOT_ENROLLED");
        return [{ type: "FleetVehicleRetired", reason: command.reason }];
      default: { const _n: never = command; throw new FleetError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "FleetVehicleEnrolled":
        return { status: "idle", id: event.id, plate: event.plate };
      case "FleetVehicleAssigned":
        if (state.status === "unknown" || state.status === "retired") return state;
        return { status: "assigned", id: state.id, plate: state.plate, driverId: event.driverId };
      case "FleetVehicleRetired":
        if (state.status === "unknown") return state;
        return { status: "retired", id: state.id, plate: state.plate };
      default: { const _n: never = event; return state; }
    }
  },
};
```

A Decider is a trio: pure `decide(command, state): Event[]` for intent, pure `evolve(state, event): State` for truth, and a literal `initialState`. The handler loads events, folds via `evolve`, calls `decide`, and appends the produced events. All I/O lives outside.

```typescript
export type GeoFenceState =
  | { status: "none" }
  | { status: "defined"; id: string; radiusM: number }
  | { status: "active"; id: string; radiusM: number }
  | { status: "breached"; id: string; radiusM: number; at: string };

export type GeoFenceCommand =
  | { type: "define"; id: string; radiusM: number }
  | { type: "activate" }
  | { type: "breach"; at: string; by: string };

export type GeoFenceEvent =
  | { type: "GeoFenceDefined"; id: string; radiusM: number }
  | { type: "GeoFenceActivated" }
  | { type: "GeoFenceBreached"; at: string; by: string };

export class GeoFenceError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const geoFenceDecider: Decider<GeoFenceCommand, GeoFenceEvent, GeoFenceState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "define":
        if (state.status !== "none") throw new GeoFenceError("EXISTS");
        if (command.radiusM <= 0) throw new GeoFenceError("BAD_RADIUS");
        return [{ type: "GeoFenceDefined", id: command.id, radiusM: command.radiusM }];
      case "activate":
        if (state.status !== "defined") throw new GeoFenceError("NOT_DEFINED");
        return [{ type: "GeoFenceActivated" }];
      case "breach":
        if (state.status !== "active") throw new GeoFenceError("NOT_ACTIVE");
        return [{ type: "GeoFenceBreached", at: command.at, by: command.by }];
      default: { const _n: never = command; throw new GeoFenceError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "GeoFenceDefined":
        return { status: "defined", id: event.id, radiusM: event.radiusM };
      case "GeoFenceActivated":
        if (state.status !== "defined") return state;
        return { status: "active", id: state.id, radiusM: state.radiusM };
      case "GeoFenceBreached":
        if (state.status !== "active") return state;
        return { status: "breached", id: state.id, radiusM: state.radiusM, at: event.at };
      default: { const _n: never = event; return state; }
    }
  },
};
