```typescript
export type DispatchBeaconState =
  | { status: "none" }
  | { status: "armed"; id: string; pulses: number }
  | { status: "fired"; id: string; pulses: number; firedAt: string };

export type DispatchBeaconCommand =
  | { type: "arm"; id: string }
  | { type: "pulse" }
  | { type: "fire"; at: string };

export type DispatchBeaconEvent =
  | { type: "DispatchBeaconArmed"; id: string }
  | { type: "DispatchBeaconPulsed" }
  | { type: "DispatchBeaconFired"; at: string };

export class BeaconError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "BeaconError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const dispatchBeaconDecider: Decider<DispatchBeaconCommand, DispatchBeaconEvent, DispatchBeaconState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "arm":
        if (state.status !== "none") throw new BeaconError("ALREADY_ARMED");
        return [{ type: "DispatchBeaconArmed", id: command.id }];
      case "pulse":
        if (state.status !== "armed") throw new BeaconError("NOT_ARMED");
        return [{ type: "DispatchBeaconPulsed" }];
      case "fire":
        if (state.status !== "armed") throw new BeaconError("NOT_ARMED");
        if (state.pulses < 1) throw new BeaconError("NO_PULSES");
        return [{ type: "DispatchBeaconFired", at: command.at }];
      default: { const _n: never = command; throw new BeaconError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DispatchBeaconArmed":
        return { status: "armed", id: event.id, pulses: 0 };
      case "DispatchBeaconPulsed":
        if (state.status !== "armed") return state;
        return { ...state, pulses: state.pulses + 1 };
      case "DispatchBeaconFired":
        if (state.status !== "armed") return state;
        return { status: "fired", id: state.id, pulses: state.pulses, firedAt: event.at };
      default: { const _n: never = event; return state; }
    }
  },
};
