```typescript
export type RouteOptimisationState =
  | { status: "none" }
  | { status: "planned"; id: string; stops: ReadonlyArray<string> }
  | { status: "rerouted"; id: string; stops: ReadonlyArray<string>; version: number }
  | { status: "completed"; id: string; stops: ReadonlyArray<string>; completedAt: string };

export type RouteOptimisationCommand =
  | { type: "plan"; id: string; stops: ReadonlyArray<string> }
  | { type: "reroute"; stops: ReadonlyArray<string> }
  | { type: "complete"; at: string };

export type RouteOptimisationEvent =
  | { type: "RoutePlanned"; id: string; stops: ReadonlyArray<string> }
  | { type: "RouteRerouted"; stops: ReadonlyArray<string> }
  | { type: "RouteCompleted"; at: string };

export class RouteError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const routeOptimisationDecider: Decider<RouteOptimisationCommand, RouteOptimisationEvent, RouteOptimisationState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "plan":
        if (state.status !== "none") throw new RouteError("ALREADY_PLANNED");
        if (command.stops.length < 2) throw new RouteError("TOO_FEW_STOPS");
        return [{ type: "RoutePlanned", id: command.id, stops: command.stops }];
      case "reroute":
        if (state.status === "completed") throw new RouteError("COMPLETED");
        if (state.status === "none") throw new RouteError("NOT_PLANNED");
        return [{ type: "RouteRerouted", stops: command.stops }];
      case "complete":
        if (state.status === "completed") throw new RouteError("ALREADY_COMPLETED");
        if (state.status === "none") throw new RouteError("NOT_PLANNED");
        return [{ type: "RouteCompleted", at: command.at }];
      default: { const _n: never = command; throw new RouteError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "RoutePlanned":
        return { status: "planned", id: event.id, stops: event.stops };
      case "RouteRerouted":
        if (state.status === "none" || state.status === "completed") return state;
        return { status: "rerouted", id: state.id, stops: event.stops, version: (state.status === "rerouted" ? state.version : 1) + 1 };
      case "RouteCompleted":
        if (state.status === "none" || state.status === "completed") return state;
        return { status: "completed", id: state.id, stops: state.stops, completedAt: event.at };
      default: { const _n: never = event; return state; }
    }
  },
};
```

A DriverAssessment aggregate uses a pure Decider: `decide` validates invariants and emits events, `evolve` folds events into state. The signing invariant lives in `decide`; state never mutates.

```typescript
export type DriverAssessmentState =
  | { status: "new" }
  | { status: "scored"; id: string; score: number }
  | { status: "signed"; id: string; score: number; signedBy: string }
  | { status: "revoked"; id: string; reason: string };

export type DriverAssessmentCommand =
  | { type: "score"; id: string; score: number }
  | { type: "sign"; signedBy: string }
  | { type: "revoke"; reason: string };

export type DriverAssessmentEvent =
  | { type: "DriverAssessmentScored"; id: string; score: number }
  | { type: "DriverAssessmentSigned"; signedBy: string }
  | { type: "DriverAssessmentRevoked"; reason: string };

export class AssessmentError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const driverAssessmentDecider: Decider<DriverAssessmentCommand, DriverAssessmentEvent, DriverAssessmentState> = {
  initialState: { status: "new" },
  decide(command, state) {
    switch (command.type) {
      case "score":
        if (state.status !== "new") throw new AssessmentError("ALREADY_SCORED");
        if (command.score < 0 || command.score > 100) throw new AssessmentError("OUT_OF_RANGE");
        return [{ type: "DriverAssessmentScored", id: command.id, score: command.score }];
      case "sign":
        if (state.status !== "scored") throw new AssessmentError("NOT_SCORED");
        return [{ type: "DriverAssessmentSigned", signedBy: command.signedBy }];
      case "revoke":
        if (state.status === "revoked") throw new AssessmentError("ALREADY_REVOKED");
        if (state.status === "new") throw new AssessmentError("NOT_SCORED");
        return [{ type: "DriverAssessmentRevoked", reason: command.reason }];
      default: { const _n: never = command; throw new AssessmentError("UNKNOWN"); }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DriverAssessmentScored":
        return { status: "scored", id: event.id, score: event.score };
      case "DriverAssessmentSigned":
        if (state.status !== "scored") return state;
        return { status: "signed", id: state.id, score: state.score, signedBy: event.signedBy };
      case "DriverAssessmentRevoked":
        if (state.status === "new") return state;
        return { status: "revoked", id: "id" in state ? state.id : "", reason: event.reason };
      default: { const _n: never = event; return state; }
    }
  },
};
