```typescript
export type TelemetryEvent =
  | { type: "TelemetryStreamOpened"; data: { id: string; source: string } }
  | { type: "TelemetrySampleIngested"; data: { value: number; at: string } }
  | { type: "TelemetryStreamSealed"; data: { at: string } };

export type TelemetryView = Readonly<{
  id: string;
  source: string;
  sampleCount: number;
  lastValue?: number;
  status: "open" | "sealed";
  sealedAt?: string;
}>;

export function when(
  current: Partial<TelemetryView>,
  event: TelemetryEvent,
): Partial<TelemetryView> {
  switch (event.type) {
    case "TelemetryStreamOpened":
      return { id: event.data.id, source: event.data.source, sampleCount: 0, status: "open" };
    case "TelemetrySampleIngested":
      return { ...current, sampleCount: (current.sampleCount ?? 0) + 1, lastValue: event.data.value };
    case "TelemetryStreamSealed":
      return { ...current, status: "sealed", sealedAt: event.data.at };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

function isTelemetryView(v: Partial<TelemetryView>): v is TelemetryView {
  return !!v.id && !!v.source && typeof v.sampleCount === "number" && !!v.status;
}

export function aggregateStream<V, E>(
  events: E[],
  reducer: (v: Partial<V>, e: E) => Partial<V>,
  check: (v: Partial<V>) => v is V,
): V {
  const folded = events.reduce<Partial<V>>(reducer, {});
  if (!check(folded)) throw new Error("INVALID_VIEW");
  return folded;
}

export function telemetryViewFrom(events: TelemetryEvent[]): TelemetryView {
  return aggregateStream<TelemetryView, TelemetryEvent>(events, when, isTelemetryView);
}
```

A projection is a pure `project(view, event): View` that folds a specific event subset into a denormalised view. Events outside interest are returned unchanged.

```typescript
export type FleetEvent =
  | { type: "FleetVehicleEnrolled"; id: string; plate: string; model: string }
  | { type: "FleetVehicleAssigned"; driverId: string; at: string }
  | { type: "FleetVehicleRetired"; reason: string }
  | { type: "FleetVehicleServiced"; km: number };

export type FleetView = Readonly<{
  id: string;
  plate: string;
  model: string;
  driverId?: string;
  assignedAt?: string;
  status: "idle" | "assigned" | "retired";
}>;

export const emptyView: FleetView = { id: "", plate: "", model: "", status: "idle" };

export function project(view: FleetView, event: FleetEvent): FleetView {
  switch (event.type) {
    case "FleetVehicleEnrolled":
      return { id: event.id, plate: event.plate, model: event.model, status: "idle" };
    case "FleetVehicleAssigned":
      return { ...view, driverId: event.driverId, assignedAt: event.at, status: "assigned" };
    case "FleetVehicleRetired":
      return { ...view, status: "retired" };
    case "FleetVehicleServiced":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function fleetViewFrom(events: FleetEvent[]): FleetView {
  return events.reduce(project, emptyView);
}
```

