```typescript
export type ParkingEvent =
  | { type: "ParkingSessionStarted"; id: string; zone: string; at: string }
  | { type: "ParkingSessionMetered"; amount: number }
  | { type: "ParkingSessionEnded"; at: string };

export type ParkingView = Readonly<{
  id: string;
  zone: string;
  startedAt: string;
  endedAt?: string;
  totalCharged: number;
  durationMinutes?: number;
  status: "active" | "ended";
}>;

export const emptyParkingView: ParkingView = {
  id: "",
  zone: "",
  startedAt: "",
  totalCharged: 0,
  status: "active",
};

export function project(view: ParkingView, event: ParkingEvent): ParkingView {
  switch (event.type) {
    case "ParkingSessionStarted":
      return {
        id: event.id,
        zone: event.zone,
        startedAt: event.at,
        totalCharged: 0,
        status: "active",
      };
    case "ParkingSessionMetered":
      return { ...view, totalCharged: view.totalCharged + event.amount };
    case "ParkingSessionEnded": {
      const started = Date.parse(view.startedAt);
      const ended = Date.parse(event.at);
      const duration = Number.isFinite(started) && Number.isFinite(ended)
        ? Math.max(0, Math.round((ended - started) / 60000))
        : undefined;
      return { ...view, status: "ended", endedAt: event.at, durationMinutes: duration };
    }
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function parkingViewFrom(events: ParkingEvent[]): ParkingView {
  return events.reduce(project, emptyParkingView);
}
```

Each snapshot is tagged `{ version, state }`. On load, you run upgraders in order from the stored version up to `CURRENT_VERSION`, each producing a new value. The final shape is type-asserted; a stored version with no upgrader path throws.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type FleetVehicleV1 = { id: string; plate: string };
export type FleetVehicleV2 = { id: string; plate: string; model: string };
export type FleetVehicleV3 = {
  id: string;
  plate: string;
  model: string;
  status: "idle" | "assigned" | "retired";
};

export type CurrentFleetVehicle = FleetVehicleV3;
export const CURRENT_VERSION = 3;

class UpgradeError extends Error {}

function v1Tov2(s: FleetVehicleV1): FleetVehicleV2 {
  return { ...s, model: "unknown" };
}

function v2Tov3(s: FleetVehicleV2): FleetVehicleV3 {
  return { ...s, status: "idle" };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentFleetVehicle> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as FleetVehicleV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as FleetVehicleV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new UpgradeError("UNSUPPORTED_VERSION");
  const out = s as CurrentFleetVehicle;
  if (!out.id || !out.plate || !out.model || !out.status) throw new UpgradeError("SHAPE");
  return { version: v, state: out };
}
```

```typescript
export type Snapshot<S> = { version: number; state: S };

export type DispatchBeaconV1 = { id: string; armed: boolean };
export type DispatchBeaconV2 = { id: string; armed: boolean; pulses: number };
export type DispatchBeaconV3 = {
  id: string;
  status: "armed" | "fired";
  pulses: number;
};

export type CurrentDispatchBeacon = DispatchBeaconV3;
export const CURRENT_VERSION = 3;

class UpgradeError extends Error {}

function v1Tov2(s: DispatchBeaconV1): DispatchBeaconV2 {
  return { ...s, pulses: 0 };
}

function v2Tov3(s: DispatchBeaconV2): DispatchBeaconV3 {
  return { id: s.id, status: s.armed ? "armed" : "fired", pulses: s.pulses };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentDispatchBeacon> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as DispatchBeaconV1); v = 2; }
  if (v === 2) { s = v2Tov3(s as DispatchBeaconV2); v = 3; }
  if (v !== CURRENT_VERSION) throw new UpgradeError("UNSUPPORTED_VERSION");
  const out = s as CurrentDispatchBeacon;
  if (!out.id || !out.status || typeof out.pulses !== "number") {
    throw new UpgradeError("SHAPE");
  }
  return { version: v, state: out };
}
```

Store each snapshot as `{ version, state }`. On load, check the version; if it's older than `CURRENT_VERSION`, run the chain of upgraders, then assert the final shape.

```typescript
export type Snapshot<S> = { version: number; state: S };

export type VehicleInspectionV1 = { id: string; odometer: number };
export type VehicleInspectionV2 = {
  id: string;
  odometer: number;
  faults: ReadonlyArray<string>;
};

export type CurrentVehicleInspection = VehicleInspectionV2;
export const CURRENT_VERSION = 2;

class SnapshotUpgradeError extends Error {}

function v1Tov2(s: VehicleInspectionV1): VehicleInspectionV2 {
  return { ...s, faults: [] };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentVehicleInspection> {
  let v = snap.version;
  let s: unknown = snap.state;
  if (v === 1) { s = v1Tov2(s as VehicleInspectionV1); v = 2; }
  if (v !== CURRENT_VERSION) throw new SnapshotUpgradeError("UNSUPPORTED");
  const out = s as CurrentVehicleInspection;
  if (!out.id || typeof out.odometer !== "number" || !Array.isArray(out.faults)) {
    throw new SnapshotUpgradeError("SHAPE");
  }
  return { version: v, state: out };
}

export function persistSnapshot(state: CurrentVehicleInspection): Snapshot<CurrentVehicleInspection> {
  return { version: CURRENT_VERSION, state };
}
