  switch (e.type) {
    case "DriverAssessmentScored":
      return { status: "scored", id: e.id, score: e.score };
    case "DriverAssessmentSigned":
      return s;
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: DriverAssessmentCommand, s: DriverAssessmentState): DriverAssessmentEvent[] {
  switch (c.type) {
    case "score":
      if (s.status !== "new") throw new AssessmentError("EXISTS");
      return [{ type: "DriverAssessmentScored", id: c.id, score: c.score }];
    case "sign":
      if (s.status !== "scored") throw new AssessmentError("NOT_SCORED");
      return [{ type: "DriverAssessmentSigned", signedBy: c.signedBy }];
    default: { const _n: never = c; throw new AssessmentError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<{ events: DriverAssessmentEvent[]; revision: bigint | null }>;
  appendToStream(stream: string, events: DriverAssessmentEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export const handleEffect = (
  command: DriverAssessmentCommand,
  ctx: { streamName: string; eventStore: EventStore },
) =>
  Effect.gen(function* () {
    const current = yield* Effect.promise(() => ctx.eventStore.readStream(ctx.streamName));
    const state = current.events.reduce(evolve, initialState);
    const events = decide(command, state);
    if (events.length === 0) return 0n;
    const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
    const revision = yield* Effect.promise(() =>
      ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision }),
    );
    return revision;
