A CommandHandler is pure orchestration: read the stream, fold to state, call `decide`, append. `decide` owns invariants; the handler only moves bytes. This keeps the domain testable without IO.

```typescript
export type VehicleInspectionState =
  | { status: "pending" }
  | { status: "inspected"; id: string; faults: ReadonlyArray<string> };

export type VehicleInspectionCommand =
  | { type: "inspect"; id: string; faults: ReadonlyArray<string> }
  | { type: "clear"; note: string };

export type VehicleInspectionEvent =
  | { type: "VehicleInspected"; id: string; faults: ReadonlyArray<string> }
  | { type: "VehicleInspectionCleared"; note: string };

export class InspectionError extends Error {}

export const initialState: VehicleInspectionState = { status: "pending" };

export function evolve(s: VehicleInspectionState, e: VehicleInspectionEvent): VehicleInspectionState {
  switch (e.type) {
    case "VehicleInspected":
      return { status: "inspected", id: e.id, faults: e.faults };
    case "VehicleInspectionCleared":
      if (s.status !== "inspected") return s;
      return { status: "inspected", id: s.id, faults: [] };
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: VehicleInspectionCommand, s: VehicleInspectionState): VehicleInspectionEvent[] {
  switch (c.type) {
    case "inspect":
      if (s.status !== "pending") throw new InspectionError("ALREADY_INSPECTED");
      return [{ type: "VehicleInspected", id: c.id, faults: c.faults }];
    case "clear":
      if (s.status !== "inspected") throw new InspectionError("NOT_INSPECTED");
      if (s.faults.length === 0) throw new InspectionError("NO_FAULTS");
      return [{ type: "VehicleInspectionCleared", note: c.note }];
    default: { const _n: never = c; throw new InspectionError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(stream: string): Promise<{ events: VehicleInspectionEvent[]; revision: bigint | null }>;
  appendToStream(stream: string, events: VehicleInspectionEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

export async function handle(
  command: VehicleInspectionCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const current = await ctx.eventStore.readStream(ctx.streamName);
  const state = current.events.reduce(evolve, initialState);
  const events = decide(command, state);
  if (events.length === 0) return;
  const expectedRevision: ExpectedRevision = current.revision ?? "no_stream";
  await ctx.eventStore.appendToStream(ctx.streamName, events, { expectedRevision });
}
