export type RouteOptimisationEvent =
  | { type: "RoutePlanned"; id: string; stops: ReadonlyArray<string> }
  | { type: "RouteRerouted"; stops: ReadonlyArray<string> }
  | { type: "RouteCompleted"; at: string };

export type EventEnvelope<E> = { position: bigint; event: E };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface EventSource<E> {
  readFrom(position: bigint): AsyncIterable<EventEnvelope<E>>;
}

export type RouteReadModel = Readonly<{ id: string; stops: ReadonlyArray<string>; status: "planned" | "rerouted" | "completed" }>;

export interface Projection<V, E> {
  load(): Promise<V>;
  project(view: V, event: E): V;
  save(view: V): Promise<void>;
}

export async function runSubscription(
  name: string,
  source: EventSource<RouteOptimisationEvent>,
  checkpoints: CheckpointStore,
  projection: Projection<RouteReadModel, RouteOptimisationEvent>,
): Promise<void> {
  const start = await checkpoints.read(name);
  let view = await projection.load();
  const iter = source.readFrom(start ?? 0n);
  const consume = async (): Promise<void> => {
    for await (const { position, event } of iter) {
      view = projection.project(view, event);
      await projection.save(view);
      await checkpoints.write(name, position);
    }
  };
  await consume();
}
```

Resume at the last checkpoint, apply each event to the read model, then persist the checkpoint. Effect.gen makes the IO sequence explicit; the pure projection stays outside.

