export type GeoFenceEvent =
  | { type: "GeoFenceDefined"; data: { id: string; radiusM: number } }
  | { type: "GeoFenceActivated"; data: { at: string } }
  | { type: "GeoFenceBreached"; data: { at: string; by: string } };

export type GeoFence = Readonly<{
  id: string;
  radiusM: number;
  status: "defined" | "active" | "breached";
  activatedAt?: string;
  breachedAt?: string;
  breachedBy?: string;
}>;

export function when(
  current: Partial<GeoFence>,
  event: GeoFenceEvent,
): Partial<GeoFence> {
  switch (event.type) {
    case "GeoFenceDefined":
      return { id: event.data.id, radiusM: event.data.radiusM, status: "defined" };
    case "GeoFenceActivated":
      return { ...current, status: "active", activatedAt: event.data.at };
    case "GeoFenceBreached":
      return { ...current, status: "breached", breachedAt: event.data.at, breachedBy: event.data.by };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (state: Partial<A>, event: E) => Partial<A>,
  check: (state: Partial<A>) => state is A,
): A {
  const folded = events.reduce<Partial<A>>(reducer, {});
  if (!check(folded)) throw new Error("INCOMPLETE_STATE");
  return folded;
}

function isGeoFence(v: Partial<GeoFence>): v is GeoFence {
  return !!v.id && typeof v.radiusM === "number" && !!v.status;
}

export function geoFenceFrom(events: GeoFenceEvent[]): GeoFence {
  return aggregateStream<GeoFence, GeoFenceEvent>(events, when, isGeoFence);
}
