  vehicleId: string;
  totalDistance: number;
  totalLitres: number;
  peakEfficiency: number;
  status: "open" | "closed";
  closedAt?: string;
}>;

export function when(
  current: Partial<FuelEfficiencyReport>,
  event: FuelEfficiencyEvent,
): Partial<FuelEfficiencyReport> {
  switch (event.type) {
    case "FuelEfficiencyReportOpened":
      return {
        id: event.data.id,
        vehicleId: event.data.vehicleId,
        totalDistance: 0,
        totalLitres: 0,
        peakEfficiency: 0,
        status: "open",
      };
    case "FuelEfficiencyRecorded": {
      const kmpl = event.data.litres > 0 ? event.data.distanceKm / event.data.litres : 0;
      return {
        ...current,
        totalDistance: (current.totalDistance ?? 0) + event.data.distanceKm,
        totalLitres: (current.totalLitres ?? 0) + event.data.litres,
        peakEfficiency: Math.max(current.peakEfficiency ?? 0, kmpl),
      };
    }
    case "FuelEfficiencyReportClosed":
      return { ...current, status: "closed", closedAt: event.data.at };
    default: {
      const _n: never = event;
      return current;
    }
  }
}

