  return !!v.id && !!v.vehicleId && typeof v.totalDistance === "number" && !!v.status;
}

export function aggregateStream<A, E>(
  events: E[],
  reducer: (s: Partial<A>, e: E) => Partial<A>,
  check: (s: Partial<A>) => s is A,
): A {
  const folded = events.reduce<Partial<A>>(reducer, {});
  if (!check(folded)) throw new Error("INVALID");
  return folded;
}

export function reportFrom(events: FuelEfficiencyEvent[]): FuelEfficiencyReport {
  return aggregateStream<FuelEfficiencyReport, FuelEfficiencyEvent>(events, when, isReport);
}
