export type RawGeoFenceEvent =
  | { type: "GeoFenceDefined"; version: 1; id: string; radius: number }
  | { type: "GeoFenceDefined"; version: 2; id: string; radiusM: number }
  | { type: "GeoFenceActivated"; version: 1 }
  | { type: "GeoFenceActivated"; version: 2; at: string }
  | { type: "GeoFenceBreached"; version: 1; at: string; by: string };

export type GeoFenceEvent =
  | { type: "GeoFenceDefined"; id: string; radiusM: number }
  | { type: "GeoFenceActivated"; at: string }
  | { type: "GeoFenceBreached"; at: string; by: string };

export type GeoFenceState =
  | { status: "none" }
  | { status: "defined"; id: string; radiusM: number }
  | { status: "active"; id: string; radiusM: number; activatedAt: string };

export class UnknownEventError extends Error {
  constructor(key: string) { super(`UNKNOWN_EVENT:${key}`); this.name = "UnknownEventError"; }
}

export function upcast(raw: RawGeoFenceEvent): GeoFenceEvent {
  switch (raw.type) {
    case "GeoFenceDefined":
      if (raw.version === 1) return { type: "GeoFenceDefined", id: raw.id, radiusM: raw.radius };
      if (raw.version === 2) return { type: "GeoFenceDefined", id: raw.id, radiusM: raw.radiusM };
      throw new UnknownEventError(`GeoFenceDefined:${(raw as { version: number }).version}`);
    case "GeoFenceActivated":
      if (raw.version === 1) return { type: "GeoFenceActivated", at: "1970-01-01T00:00:00Z" };
      if (raw.version === 2) return { type: "GeoFenceActivated", at: raw.at };
      throw new UnknownEventError(`GeoFenceActivated:${(raw as { version: number }).version}`);
    case "GeoFenceBreached":
      if (raw.version === 1) return { type: "GeoFenceBreached", at: raw.at, by: raw.by };
      throw new UnknownEventError(`GeoFenceBreached:${(raw as { version: number }).version}`);
    default: {
      const _n: never = raw;
      throw new UnknownEventError("UNKNOWN");
    }
  }
}

export function evolve(state: GeoFenceState, event: GeoFenceEvent): GeoFenceState {
  switch (event.type) {
    case "GeoFenceDefined":
      return { status: "defined", id: event.id, radiusM: event.radiusM };
    case "GeoFenceActivated":
      if (state.status !== "defined") return state;
      return { status: "active", id: state.id, radiusM: state.radiusM, activatedAt: event.at };
    case "GeoFenceBreached":
      return state;
    default: { const _n: never = event; return state; }
  }
}

export function replayRaw(raws: RawGeoFenceEvent[]): GeoFenceState {
  const upcasted: GeoFenceEvent[] = raws.map(upcast);
  let state: GeoFenceState = { status: "none" };
  for (const e of upcasted) {
    state = evolve(state, e);
  }
  return state;
}
```

Upcasting runs at read time. Each stored event carries a `version`; the upcaster switches on `{ type, version }` and returns the canonical current shape. The projection consumes only the current shape, so it never sees legacy payloads.

```typescript
export type RawDispatchBeaconEvent =
  | { type: "DispatchBeaconArmed"; version: 1; id: string }
  | { type: "DispatchBeaconArmed"; version: 2; id: string; priority: "low" | "high" }
  | { type: "DispatchBeaconPulsed"; version: 1 }
  | { type: "DispatchBeaconFired"; version: 1; at: string };

export type DispatchBeaconEvent =
  | { type: "DispatchBeaconArmed"; id: string; priority: "low" | "high" }
  | { type: "DispatchBeaconPulsed" }
  | { type: "DispatchBeaconFired"; at: string };

export type DispatchBeaconView = Readonly<{
  id: string;
  priority: "low" | "high";
  pulses: number;
  firedAt?: string;
}>;

export const emptyBeaconView: DispatchBeaconView = { id: "", priority: "low", pulses: 0 };

export class UnknownEventError extends Error {}

export function upcast(raw: RawDispatchBeaconEvent): DispatchBeaconEvent {
  switch (raw.type) {
    case "DispatchBeaconArmed":
      if (raw.version === 1) return { type: "DispatchBeaconArmed", id: raw.id, priority: "low" };
      if (raw.version === 2) return { type: "DispatchBeaconArmed", id: raw.id, priority: raw.priority };
      throw new UnknownEventError(`Armed:${(raw as { version: number }).version}`);
    case "DispatchBeaconPulsed":
      if (raw.version === 1) return { type: "DispatchBeaconPulsed" };
      throw new UnknownEventError(`Pulsed:${(raw as { version: number }).version}`);
    case "DispatchBeaconFired":
      if (raw.version === 1) return { type: "DispatchBeaconFired", at: raw.at };
      throw new UnknownEventError(`Fired:${(raw as { version: number }).version}`);
    default: {
      const _n: never = raw;
      throw new UnknownEventError("UNKNOWN_TYPE");
    }
  }
}

export function project(view: DispatchBeaconView, event: DispatchBeaconEvent): DispatchBeaconView {
  switch (event.type) {
    case "DispatchBeaconArmed":
      return { id: event.id, priority: event.priority, pulses: 0 };
    case "DispatchBeaconPulsed":
      return { ...view, pulses: view.pulses + 1 };
    case "DispatchBeaconFired":
      return { ...view, firedAt: event.at };
    default: { const _n: never = event; return view; }
  }
}

export function viewFromRaw(raws: RawDispatchBeaconEvent[]): DispatchBeaconView {
  let view: DispatchBeaconView = emptyBeaconView;
  for (const raw of raws) {
    view = project(view, upcast(raw));
  }
  return view;
}
