export type RouteCommand =
  | { type: "plan"; id: string; stops: ReadonlyArray<string> }
  | { type: "complete"; at: string };

export class DomainError extends Error {}

export const initialState: RouteState = { status: "none" };

export function evolve(s: RouteState, e: RouteOptimisationEvent): RouteState {
  switch (e.type) {
    case "RoutePlanned":
      return { status: "planned", id: e.id, stops: e.stops };
    case "RouteRerouted":
      if (s.status !== "planned") return s;
      return { ...s, stops: e.stops };
    case "RouteCompleted":
      return s;
    default: { const _n: never = e; return s; }
  }
}

export function decide(c: RouteCommand, s: RouteState): RouteOptimisationEvent[] {
  switch (c.type) {
    case "plan":
      if (s.status !== "none") throw new DomainError("EXISTS");
      return [{ type: "RoutePlanned", id: c.id, stops: c.stops }];
    case "complete":
      if (s.status !== "planned") throw new DomainError("NOT_PLANNED");
      return [{ type: "RouteCompleted", at: c.at }];
    default: { const _n: never = c; throw new DomainError("UNKNOWN"); }
  }
}

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  readStream(s: string): Promise<{ events: RouteOptimisationEvent[]; revision: bigint | null }>;
  appendToStream(s: string, e: RouteOptimisationEvent[], o: { expectedRevision: ExpectedRevision }): Promise<bigint>;
}

