export function react(event: SagaInput): RouteCommand | null {
  switch (event.type) {
    case "DispatchBeaconArmed":
      return null;
    case "DispatchBeaconPulsed":
      return { type: "planRoute", routeId: `route-${event.id}`, beaconId: event.id };
    case "DispatchBeaconFired":
      return { type: "completeRoute", at: event.at };
    case "RoutePlanned":
