export type SagaEvent =
  | { type: "GeoFenceBreached"; fenceId: string; vehicleId: string; at: string }
  | { type: "FleetVehicleDispatched"; vehicleId: string }
  | { type: "FleetVehicleReturned"; vehicleId: string };

export type SagaCommand =
  | { type: "dispatchFleetVehicle"; vehicleId: string; fenceId: string }
  | { type: "closeIncident"; vehicleId: string };

export type SagaState =
  | { status: "idle" }
  | { status: "dispatched"; vehicleId: string; fenceId: string };

export interface SagaStep {
  readonly nextState: SagaState;
  readonly command?: SagaCommand;
}

export function react(state: SagaState, event: SagaEvent): SagaStep {
  switch (event.type) {
    case "GeoFenceBreached":
      if (state.status !== "idle") return { nextState: state };
      return {
        nextState: { status: "dispatched", vehicleId: event.vehicleId, fenceId: event.fenceId },
        command: { type: "dispatchFleetVehicle", vehicleId: event.vehicleId, fenceId: event.fenceId },
      };
    case "FleetVehicleDispatched":
      return { nextState: state };
    case "FleetVehicleReturned":
      if (state.status !== "dispatched") return { nextState: state };
      return {
        nextState: { status: "idle" },
        command: { type: "closeIncident", vehicleId: state.vehicleId },
      };
    default: {
      const _n: never = event;
      return { nextState: state };
    }
  }
}

// Projection helper: fold a saga event stream into the final SagaState and the commands emitted.
export function project(
  init: SagaState,
  events: ReadonlyArray<SagaEvent>,
): { state: SagaState; commands: ReadonlyArray<SagaCommand> } {
  let state = init;
  const commands: SagaCommand[] = [];
  for (const e of events) {
    const step = react(state, e);
    state = step.nextState;
    if (step.command !== undefined) commands.push(step.command);
  }
  return { state, commands };
}
