  | { type: "record"; distanceKm: number; litres: number }
  | { type: "close"; at: string };

export type FuelEfficiencyReportEvent =
  | { type: "FuelEfficiencyReportOpened"; id: string }
  | { type: "FuelEfficiencyRecorded"; distanceKm: number; litres: number }
  | { type: "FuelEfficiencyReportClosed"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export function decide(
  command: FuelEfficiencyReportCommand,
  state: FuelEfficiencyReportState,
): FuelEfficiencyReportEvent[] {
  switch (command.type) {
    case "open":
      if (state.status !== "none") throw new DomainError("ALREADY_OPEN");
      return [{ type: "FuelEfficiencyReportOpened", id: command.id }];
    case "record":
      if (state.status !== "open") throw new DomainError("NOT_OPEN");
      if (command.distanceKm <= 0) throw new DomainError("BAD_DISTANCE");
      if (command.litres <= 0) throw new DomainError("BAD_LITRES");
      return [{ type: "FuelEfficiencyRecorded", distanceKm: command.distanceKm, litres: command.litres }];
    case "close":
      if (state.status !== "open") throw new DomainError("NOT_OPEN");
      return [{ type: "FuelEfficiencyReportClosed", at: command.at }];
    default: {
      const _n: never = command;
      throw new DomainError("UNKNOWN");
    }
  }
}
